#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <time.h>

/*
 * Reinforcement Learning: Q-Learning in Grid World
 * Demonstrates RL as a machine learning paradigm
 */

#define GRID_SIZE 4
#define NUM_ACTIONS 4 // 0=up, 1=down, 2=left, 3=right
#define NUM_EPISODES 500
#define MAX_STEPS 100
#define ALPHA 0.1 // Learning rate
#define GAMMA 0.9 // Discount factor
#define EPSILON 0.1 // Exploration rate

// Q-table: Q[state][action]
double Q[GRID_SIZE * GRID_SIZE][NUM_ACTIONS];

// Goal state
int goal_state = 15; // Bottom-right corner

// Structure for state-action-reward experience
typedef struct {
 int state;
 int action;
 int next_state;
 double reward;
 int done;
} Experience;

/* Get action name for display */
const char* get_action_name(int action) {
 switch(action) {
 case 0: return "UP";
 case 1: return "DOWN";
 case 2: return "LEFT";
 case 3: return "RIGHT";
 default: return "UNKNOWN";
 }
}

/* Initialize Q-table to zeros */
void initialize_q_table() {
 for (int i = 0; i < GRID_SIZE * GRID_SIZE; i++) {
 for (int j = 0; j < NUM_ACTIONS; j++) {
 Q[i][j] = 0.0;
 }
 }
}

/* Epsilon-greedy action selection */
int select_action(int state) {
 if ((double)rand() / RAND_MAX < EPSILON) {
 // Exploration: random action
 return rand() % NUM_ACTIONS;
 } else {
 // Exploitation: best known action
 int best_action = 0;
 double best_value = Q[state][0];

 for (int a = 1; a < NUM_ACTIONS; a++) {
 if (Q[state][a] > best_value) {
 best_value = Q[state][a];
 best_action = a;
 }
 }
 return best_action;
 }
}

/* Execute action in environment, return experience */
Experience step(int state, int action) {
 Experience exp;
 exp.state = state;
 exp.action = action;

 // Calculate next state based on action
 int row = state / GRID_SIZE;
 int col = state % GRID_SIZE;

 int new_row = row;
 int new_col = col;

 switch(action) {
 case 0: new_row = (row > 0) ? row - 1 : row; break; // UP
 case 1: new_row = (row < GRID_SIZE-1) ? row + 1 : row; break; // DOWN
 case 2: new_col = (col > 0) ? col - 1 : col; break; // LEFT
 case 3: new_col = (col < GRID_SIZE-1) ? col + 1 : col; break; // RIGHT
 }

 exp.next_state = new_row * GRID_SIZE + new_col;

 // Calculate reward
 if (exp.next_state == goal_state) {
 exp.reward = 100.0; // Goal reached!
 exp.done = 1;
 } else {
 exp.reward = -1.0; // Step penalty (encourages shortest path)
 exp.done = 0;
 }

 return exp;
}

/* Q-Learning update rule */
void learn(Experience exp) {
 // Q(s,a) = Q(s,a) + alpha * [reward + gamma * max(Q(s',a')) - Q(s,a)]

 double max_next_q = 0.0;
 if (!exp.done) {
 // Find max Q value for next state
 for (int a = 0; a < NUM_ACTIONS; a++) {
 if (Q[exp.next_state][a] > max_next_q) {
 max_next_q = Q[exp.next_state][a];
 }
 }
 }

 double td_target = exp.reward + GAMMA * max_next_q;
 double td_error = td_target - Q[exp.state][exp.action];

 Q[exp.state][exp.action] += ALPHA * td_error;
}

/* Run one episode */
double run_episode() {
 int state = 0; // Start at top-left
 double total_reward = 0.0;

 for (int step = 0; step < MAX_STEPS; step++) {
 // Agent selects action
 int action = select_action(state);

 // Environment responds
 Experience exp = step(state, action);

 // Agent learns from experience
 learn(exp);

 total_reward += exp.reward;
 state = exp.next_state;

 if (exp.done) break;
 }

 return total_reward;
}

/* Extract and display learned policy */
void display_policy() {
 printf("\nLearned Policy (Optimal Actions):\n");
 printf(" ");
 for (int col = 0; col < GRID_SIZE; col++) printf(" %d ", col);
 printf("\n");

 for (int row = 0; row < GRID_SIZE; row++) {
 printf(" %d ", row);
 for (int col = 0; col < GRID_SIZE; col++) {
 int state = row * GRID_SIZE + col;
 if (state == goal_state) {
 printf(" GOAL");
 } else {
 // Find best action
 int best_a = 0;
 for (int a = 1; a < NUM_ACTIONS; a++) {
 if (Q[state][a] > Q[state][best_a]) best_a = a;
 }
 printf(" %s", get_action_name(best_a));
 }
 }
 printf("\n");
 }
}

int main() {
 srand(time(NULL));

 printf("==============================================\n");
 printf(" Reinforcement Learning: Q-Learning Demo\n");
 printf("==============================================\n\n");

 printf("Grid World: %dx%d\n", GRID_SIZE, GRID_SIZE);
 printf("Start: (0,0) Goal: (%d,%d)\n\n", GRID_SIZE-1, GRID_SIZE-1);

 initialize_q_table();

 printf("Training agent using Q-Learning...\n");
 printf("Parameters: alpha=%.2f, gamma=%.2f, epsilon=%.2f\n\n", 
 ALPHA, GAMMA, EPSILON);

 // Training loop
 for (int ep = 1; ep <= NUM_EPISODES; ep++) {
 double reward = run_episode();

 if (ep % 100 == 0) {
 printf("Episode %d: Total Reward = %.2f\n", ep, reward);
 }
 }

 // Display results
 printf("\n==============================================\n");
 printf(" Training Complete!\n");
 printf("==============================================\n");

 display_policy();

 printf("\n--- RL vs Other ML Paradigms ---\n");
 printf("SUPERVISED: Needs labeled (state, optimal_action) pairs\n");
 printf("UNSUPERVISED: Finds patterns without any feedback\n");
 printf("RL: Learns from reward signal through interaction\n");
 printf(" Discovers optimal policy via trial-and-error\n");

 return 0;
}
